BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?dependency ?depType ?client ?clientName ?supplier ?supplierName WHERE {
  ?requirement vocab:NamedElement_name "High%20signal%20exposures" .
  ?requirement rdf:type vocab:tmt%20requirement .

  # Find any dependency where requirement is either client or supplier
  {
    ?dependency vocab:Dependency_client ?requirement .
    ?dependency vocab:Dependency_supplier ?supplier .
    BIND(?requirement AS ?client)
  }
  UNION
  {
    ?dependency vocab:Dependency_supplier ?requirement .
    ?dependency vocab:Dependency_client ?client .
    BIND(?requirement AS ?supplier)
  }

  ?dependency rdf:type ?depType .
  OPTIONAL { ?client vocab:NamedElement_name ?clientName }
  OPTIONAL { ?supplier vocab:NamedElement_name ?supplierName }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?prop ?value ?valueName WHERE {
  ?requirement vocab:NamedElement_name "High%20signal%20exposures" .
  ?requirement vocab:Element_ownedElement ?instance .

  ?instance ?prop ?value .
  OPTIONAL { ?value vocab:NamedElement_name ?valueName }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?slot ?definingFeature ?value ?valueName WHERE {
  ?requirement vocab:NamedElement_name "High%20signal%20exposures" .
  ?requirement vocab:Element_ownedElement ?instance .
  ?instance vocab:InstanceSpecification_slot ?slot .

  OPTIONAL { ?slot vocab:Slot_definingFeature ?definingFeature }
  OPTIONAL { ?slot vocab:Slot_value ?value }
  OPTIONAL { ?value vocab:NamedElement_name ?valueName }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?verifyDep ?client ?clientName ?supplier ?supplierName WHERE {
  ?verifyDep rdf:type vocab:verify .
  ?verifyDep vocab:Dependency_client ?client .
  ?verifyDep vocab:Dependency_supplier ?supplier .

  OPTIONAL { ?client vocab:NamedElement_name ?clientName }
  OPTIONAL { ?supplier vocab:NamedElement_name ?supplierName }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?dep ?depType ?client ?clientName ?supplier ?supplierName WHERE {
  # Search for any dependency related to "High signal exposures" requirement
  ?requirement vocab:NamedElement_name "High%20signal%20exposures" .

  # Check all possible dependency relationships
  {
    ?dep vocab:Dependency_client ?requirement .
    ?dep vocab:Dependency_supplier ?supplier .
    BIND(?requirement AS ?client)
  }
  UNION
  {
    ?dep vocab:Dependency_supplier ?requirement .
    ?dep vocab:Dependency_client ?client .
    BIND(?requirement AS ?supplier)
  }
  UNION
  {
    ?dep vocab:Dependency_client ?client .
    ?dep vocab:Dependency_supplier ?supplier .
    FILTER(?client = ?requirement || ?supplier = ?requirement)
  }

  ?dep rdf:type ?depType .
  OPTIONAL { ?client vocab:NamedElement_name ?clientName }
  OPTIONAL { ?supplier vocab:NamedElement_name ?supplierName }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?dep ?depType ?client ?clientName ?supplier ?supplierName WHERE {
  # Search for ALL dependencies in the model to understand the pattern
  ?dep rdf:type ?depType .
  ?dep vocab:Dependency_client ?client .
  ?dep vocab:Dependency_supplier ?supplier .

  OPTIONAL { ?client vocab:NamedElement_name ?clientName }
  OPTIONAL { ?supplier vocab:NamedElement_name ?supplierName }

  FILTER(?depType IN (vocab:verify, vocab:satisfy, vocab:allocate))
}
LIMIT 50
